"use strict";const test=require("tape"),fastURI=require(".."),fn=fastURI.equal,runTest=(t,e)=>{e.forEach(e=>{const a=e.result?"==":"!=";t.equal(fn(e.pair[0],e.pair[1]),e.result,`${e.pair[0]} ${a} ${e.pair[1]}`),t.equal(fn(e.pair[1],e.pair[0]),e.result,`${e.pair[1]} ${a} ${e.pair[0]}`)})};test("URI Equals",t=>{runTest(t,[{pair:["example://a/b/c/%7Bfoo%7D","eXAMPLE://a/./b/../b/%63/%7bfoo%7d"],result:!0},{pair:["http://example.org/~user","http://example.org/%7euser"],result:!0}]),t.end()}),test("HTTP Equals",t=>{runTest(t,[{pair:["http://abc.com:80/~smith/home.html","http://abc.com/~smith/home.html"],result:!0},{pair:[{scheme:"http",host:"abc.com",port:80,path:"/~smith/home.html"},"http://abc.com/~smith/home.html"],result:!0},{pair:["http://ABC.com/%7Esmith/home.html","http://abc.com/~smith/home.html"],result:!0},{pair:["http://ABC.com:/%7esmith/home.html","http://abc.com/~smith/home.html"],result:!0},{pair:["HTTP://ABC.COM","http://abc.com/"],result:!0},{pair:["http://example.com:/","http://example.com:80/"],result:!0}]),t.end()}),test("HTTPS Equals",t=>{runTest(t,[{pair:["https://example.com","https://example.com:443/"],result:!0},{pair:["https://example.com:/","https://example.com:443/"],result:!0}]),t.end()}),test("URN Equals",t=>{runTest(t,[{pair:["urn:foo:a123,456","urn:foo:a123,456"],result:!0},{pair:["urn:foo:a123,456","URN:foo:a123,456"],result:!0},{pair:["urn:foo:a123,456","urn:FOO:a123,456"],result:!0}]),t.throws(()=>{fn("urn:","urn:FOO:a123,456")},"URN without nid cannot be serialized"),t.end()}),test("UUID Equals",t=>{runTest(t,[{pair:["URN:UUID:F81D4FAE-7DEC-11D0-A765-00A0C91E6BF6","urn:uuid:f81d4fae-7dec-11d0-a765-00a0c91e6bf6"],result:!0}]),t.end()}),test("WS Equal",t=>{runTest(t,[{pair:["WS://ABC.COM:80/chat#one","ws://abc.com/chat"],result:!0}]),t.end()}),test("WSS Equal",t=>{runTest(t,[{pair:["WSS://ABC.COM:443/chat#one","wss://abc.com/chat"],result:!0}]),t.end()}),test("URI Equals tolerates malformed fragments",t=>{t.equal(fastURI.equal("http://example.com/#%E0%A4A","http://example.com/#%E0%A4A"),!0,"malformed fragment does not throw during equality checks"),t.end()});